'use client';

import { useState } from 'react';
import {
  ChevronDown, Grid2X2, Search, MousePointerClick,
  Share2, PenTool, LayoutTemplate, BarChart3, Menu, X,
} from 'lucide-react';

// ─── Type definitions ──────────────────────────────────
interface ServiceItem {
  Icon: React.ElementType;
  title: string;
  desc: string;
}

// ─── Data constants ────────────────────────────────────
const SERVICES: ServiceItem[] = [
  { Icon: Search,           title: 'Search Engine Optimization', desc: 'Rank higher and get more organic traffic'     },
  { Icon: MousePointerClick,title: 'Pay-Per-Click Advertising',   desc: 'Targeted ads to boost your sales instantly'  },
  { Icon: Share2,           title: 'Social Media Marketing',       desc: 'Build your community and engage audiences'  },
  { Icon: PenTool,          title: 'Content Creation',             desc: 'Compelling content that drives conversions' },
  { Icon: LayoutTemplate,   title: 'Web Development',              desc: 'Fast, modern, and responsive websites'      },
  { Icon: BarChart3,        title: 'Analytics & Reporting',        desc: 'Data-driven insights for continuous growth' },
];

const SIMPLE_NAV_LINKS = ['Case Studies', 'About Us', 'Contact'];

// ─── Shared class constants ────────────────────────────
const navBtn =
  'flex items-center gap-[3px] text-[13.5px] font-medium text-[#444] ' +
  'bg-transparent border-none cursor-pointer transition-[color,background] duration-150 ' +
  'whitespace-nowrap py-2 px-3 rounded-lg hover:text-[#111] hover:bg-[#f4f4f4] ' +
  'w-full md:w-auto text-left';

const dropdownPanel =
  'flex-col ' +
  'md:absolute md:top-[calc(100%+10px)] md:left-0 md:bg-white md:border-[1.5px] ' +
  'md:border-[#111] md:rounded-xl md:shadow-[0_10px_30px_rgba(0,0,0,0.08)] ' +
  'md:w-[360px] md:p-6 md:z-[100] md:gap-5 ' +
  'before:absolute before:content-[""] before:w-full before:h-[20px] before:-top-[20px] before:left-0 ' +
  'max-md:border-l-2 max-md:border-l-[#f0f0f0] max-md:w-full max-md:p-[10px_0_0_10px] max-md:gap-4';

// ─── Sub-components ────────────────────────────────────
function ServiceLink({ Icon, title, desc }: ServiceItem) {
  return (
    <a href="#" className="flex items-start gap-4 no-underline text-inherit transition-opacity duration-150 hover:opacity-60">
      <div className="mt-[2px] text-[#333]"><Icon size={18} /></div>
      <div>
        <div className="text-[14.5px] font-semibold text-[#111] mb-1">{title}</div>
        <div className="text-[13px] text-[#666] leading-[1.4]">{desc}</div>
      </div>
    </a>
  );
}

// ─── Main component ────────────────────────────────────
export default function Navbar() {
  const [menuOpen,      setMenuOpen]      = useState(false);
  const [servicesOpen,  setServicesOpen]  = useState(false);
  const [resourcesOpen, setResourcesOpen] = useState(false);

  return (
    <header className="flex justify-center pt-5 px-4 sm:px-6 sticky top-0 z-[100] w-full">
      <nav className="flex items-center justify-between bg-white/70 backdrop-blur-md border border-[#e5e5e5] rounded-xl py-3 px-4 sm:px-5 w-full max-w-[1080px] shadow-sm relative mx-auto">

        {/* Logo */}
        <div className="flex items-center gap-2.5">
          <img src="/halalogo.png" alt="Hala Logo" className="h-[26px] w-auto" />
          <span className="font-poppins text-[15px] font-bold tracking-[-0.3px] text-[#111]">Hala Technologies</span>
        </div>

        {/* Mobile hamburger */}
        <button
          className="block md:hidden bg-transparent border-none cursor-pointer text-[#111] p-1"
          onClick={() => setMenuOpen(prev => !prev)}
          aria-label={menuOpen ? 'Close menu' : 'Open menu'}
        >
          {menuOpen ? <X size={24} /> : <Menu size={24} />}
        </button>

        {/* Nav content */}
        <div
          className={
            `${menuOpen ? 'flex' : 'hidden'} flex-col items-start p-6 gap-4 ` +
            'absolute top-[calc(100%+10px)] left-0 right-0 ' +
            'bg-white border border-[#e5e5e5] rounded-[18px] shadow-[0_10px_30px_rgba(0,0,0,0.1)] z-[100] ' +
            'md:static md:flex md:flex-row md:items-center md:gap-4 ' +
            'md:bg-transparent md:border-0 md:shadow-none md:rounded-none md:p-0 md:z-auto'
          }
        >
          <ul className="flex flex-col items-start gap-4 list-none m-0 p-0 w-full md:flex-row md:items-center md:gap-4 md:w-auto">

            {/* Services dropdown */}
            <li className="relative group w-full md:w-auto" onMouseLeave={() => setServicesOpen(false)}>
              <button className={navBtn} onClick={() => setServicesOpen(prev => !prev)}>
                Services
                <ChevronDown
                  size={14}
                  className="transition-transform duration-200"
                  style={{ transform: servicesOpen ? 'rotate(180deg)' : 'none' }}
                />
              </button>
              <div className={`${servicesOpen ? 'flex' : 'hidden'} group-hover:flex ${dropdownPanel}`}>
                <div className="text-[11px] font-semibold text-[#666] tracking-[0.5px] uppercase mb-[2px]">
                  OUR SERVICES
                </div>
                {SERVICES.map(item => <ServiceLink key={item.title} {...item} />)}
              </div>
            </li>

            {/* Simple links */}
            {SIMPLE_NAV_LINKS.map(label => (
              <li key={label} className="w-full md:w-auto">
                <button className={navBtn}>{label}</button>
              </li>
            ))}

            {/* Resources dropdown */}
            <li className="relative group w-full md:w-auto" onMouseLeave={() => setResourcesOpen(false)}>
              <button className={navBtn} onClick={() => setResourcesOpen(prev => !prev)}>
                Resources
                <ChevronDown
                  size={14}
                  className="transition-transform duration-200"
                  style={{ transform: resourcesOpen ? 'rotate(180deg)' : 'none' }}
                />
              </button>
              <div className={`${resourcesOpen ? 'flex' : 'hidden'} group-hover:flex ${dropdownPanel}`}>
                <div className="text-[11px] font-semibold text-[#666] tracking-[0.5px] uppercase mb-[2px]">
                  OUR RESOURCES
                </div>
                <a href="#" className="flex items-start gap-4 no-underline text-inherit transition-opacity duration-150 hover:opacity-60">
                  <div>
                    <div className="text-[14.5px] font-semibold text-[#111] mb-1">Blog</div>
                    <div className="text-[13px] text-[#666] leading-[1.4]">Latest news and articles</div>
                  </div>
                </a>
              </div>
            </li>

          </ul>

          {/* CTA + separator */}
          <div className="flex items-center gap-4 w-full md:w-auto mt-4 md:mt-0">
            <div className="hidden md:block w-px h-8 bg-[#e0e0e0]" />
            <button className="flex items-center justify-center gap-[7px] py-2.5 px-5 bg-[#111] text-white rounded-lg text-[13.5px] font-semibold cursor-pointer transition-colors duration-150 whitespace-nowrap hover:bg-[#333] w-full md:w-auto shadow-sm">
              <Grid2X2 size={16} />
              Lets Talk
            </button>
          </div>

        </div>
      </nav>
    </header>
  );
}
